 // Create a map to handle duplicates with configKeyName as key
    const configMap = new Map();
    let configNames = [];
    let configParamValues = page.variables.allConfigValues;
    let i = 0;
    let defaultValue = "";
    configParamValues.forEach(configItem => {
        // Check if dimensions array exists and has at least one element
        if (!configItem.dimensions || !Array.isArray(configItem.dimensions) || configItem.dimensions.length === 0) {
            return; // Skip this item
        }

        if (configItem.dimensions.length === 1) {
          defaultValue = configItem.value.string_value;
        }

        // Get the 0th object from dimensions array
        const firstDimension = configItem.dimensions[0];
        if (!firstDimension || !firstDimension.string_value) {
            return; // Skip if string_value doesn't exist
        }

        const configKeyName = firstDimension.string_value;
        const configDataType = configItem.value?.type || 'NA';
        const createdBy = configItem.created_by?.email_id || 'NA';
        const createdTime = configItem.created_time?.seconds || '0';
        const updatedBy = configItem.updated_by?.email_id || createdBy;
        const updatedTime = configItem.updated_time?.seconds || createdTime;

        // Convert timestamp to date format dd-mm-yyyy hh-mm-ss
        function formatTimestamp(timestamp) {
            try {
                const date = new Date(parseInt(timestamp) * 1000);
                if (isNaN(date.getTime())) return 'Invalid Date';

                const day = String(date.getDate()).padStart(2, '0');
                const month = String(date.getMonth() + 1).padStart(2, '0');
                const year = date.getFullYear();
                const hours = String(date.getHours()).padStart(2, '0');
                const minutes = String(date.getMinutes()).padStart(2, '0');
                const seconds = String(date.getSeconds()).padStart(2, '0');

                return `${day}/${month}/${year} \n at ${hours}:${minutes}:${seconds}`;
            } catch (error) {
                return '';
            }
        }

        if (configMap.has(configKeyName)) {
            // Update existing entry with oldest created time and newest updated time
            const existing = configMap.get(configKeyName);

            // Keep oldest created time
            if (parseInt(createdTime) < parseInt(existing.createdTimeSeconds)) {
                existing.createdByWithTime = `${createdBy} on \n ${formatTimestamp(createdTime)}`;
                existing.createdTimeSeconds = createdTime;
            }

            // Keep newest updated time
            if (parseInt(updatedTime) > parseInt(existing.updatedTimeSeconds)) {
                existing.lastUpdatedByWithTime = `${updatedBy} on \n ${formatTimestamp(updatedTime)}`;
                existing.updatedTimeSeconds = updatedTime;
            }
        } else {
            // Create new entry
          configNames.push(configKeyName);
            configMap.set(configKeyName, {
                configKeyName: configKeyName,
                cnfigDefaultValue: defaultValue,
                configDataType: configDataType,
                createdByWithTime: `${createdBy} on \n ${formatTimestamp(createdTime)}`,
                lastUpdatedByWithTime: `${updatedBy} on \n ${formatTimestamp(updatedTime)}`,
                createdTimeSeconds: createdTime, // Store for comparison
                updatedTimeSeconds: updatedTime,  // Store for comparison
                ind: i
            });
          i++;
        }
    });

    // Convert map to array and remove temporary timestamp fields
    let resultArray = Array.from(configMap.values()).map(item => ({
        configKeyName: item.configKeyName,
        configDefaultValue: item.cnfigDefaultValue,
        configDataType: item.configDataType,
        createdByWithTime: item.createdByWithTime,
        lastUpdatedByWithTime: item.lastUpdatedByWithTime,
        ind: item.ind
    }));
//appConfigEntries.setValue(resultArray);
//appFilteredConfigEntries.setValue(resultArray);
//appConfigNames.setValue(configNames);

await actions.setPageVariable("appConfigEntries",resultArray)
await actions.setPageVariable("appFilteredConfigEntries",resultArray)
await actions.setPageVariable("appConfigNames",configNames)
